"use client";

import { useMemo, useState } from "react";

const sizeOptions = [
    {
        value: "pequeno",
        label: "Pequeno"
    },
    {
        value: "medio",
        label: "Médio"
    },
    {
        value: "grande",
        label: "Grande"
    }
];

const serviceOptions = [
    {
        value: "banho",
        label: "Banho"
    },
    {
        value: "banho-tosa",
        label: "Banho + tosa"
    }
];

const frequencyOptions = [
    {
        value: "avulso",
        label: "Avulso"
    },
    {
        value: "mensal",
        label: "Mensal"
    }
];

const estimateRanges = {
    avulso: {
        banho: {
            pequeno: [60, 75],
            medio: [80, 95],
            grande: [100, 130]
        },
        "banho-tosa": {
            pequeno: [90, 120],
            medio: [120, 150],
            grande: [150, 190]
        }
    },
    mensal: {
        banho: {
            pequeno: [110, 130],
            medio: [150, 175],
            grande: [190, 230]
        },
        "banho-tosa": {
            pequeno: [150, 190],
            medio: [200, 240],
            grande: [250, 310]
        }
    }
} as const;

type Size = keyof typeof estimateRanges.avulso.banho;
type Service = keyof typeof estimateRanges.avulso;
type Frequency = keyof typeof estimateRanges;

export default function PricingSimulator({
    whatsAppUrl
}: Readonly<{
    whatsAppUrl: string;
}>) {
    const [size, setSize] = useState<Size>("pequeno");
    const [service, setService] = useState<Service>("banho");
    const [frequency, setFrequency] = useState<Frequency>("avulso");

    const estimate = useMemo(() => {
        const [min, max] = estimateRanges[frequency][service][size];

        return `Valor estimado: R$ ${min} – R$ ${max}`;
    }, [frequency, service, size]);

    return (
        <section className="simulator-card" aria-labelledby="simulator-title">
            <div>
                <span className="eyebrow">Simule seu atendimento</span>
                <h3 id="simulator-title">Simule seu atendimento</h3>
                <p>
                    Uma estimativa rápida para orientar a conversa. O valor final é confirmado pelo
                    WhatsApp.
                </p>
            </div>

            <div className="simulator-controls">
                <label>
                    Porte
                    <select
                        value={size}
                        onChange={(event) => setSize(event.target.value as Size)}
                    >
                        {sizeOptions.map((option) => (
                            <option key={option.value} value={option.value}>
                                {option.label}
                            </option>
                        ))}
                    </select>
                </label>

                <label>
                    Serviço
                    <select
                        value={service}
                        onChange={(event) => setService(event.target.value as Service)}
                    >
                        {serviceOptions.map((option) => (
                            <option key={option.value} value={option.value}>
                                {option.label}
                            </option>
                        ))}
                    </select>
                </label>

                <label>
                    Frequência
                    <select
                        value={frequency}
                        onChange={(event) => setFrequency(event.target.value as Frequency)}
                    >
                        {frequencyOptions.map((option) => (
                            <option key={option.value} value={option.value}>
                                {option.label}
                            </option>
                        ))}
                    </select>
                </label>
            </div>

            <div className="simulator-result" aria-live="polite">
                <strong>{estimate}</strong>
                <span>Estimativa simples. Confirme disponibilidade, porte e busca pelo WhatsApp.</span>
            </div>

            <a
                className="button button-primary"
                href={whatsAppUrl}
                target="_blank"
                rel="noreferrer"
                aria-label="Confirmar valor estimado pelo WhatsApp"
            >
                Confirmar pelo WhatsApp
            </a>
        </section>
    );
}
